1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
15	
16	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
17	type Damage = { itemType: string; amount: number };
18	type Incident = { cause: string; damages: Damage[] };
19	type QuoteStep = { op: "quote"; items: Item[] };
20	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
21	type Step = QuoteStep | ClaimStep;
22	type Customer = { yearsWithMHPCO: number };
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	type ItemTypeSpec = { basePremium: number; insuranceValue: number; isComponent: boolean };
26	
27	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
28	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
29	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
30	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
31	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
32	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
33	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
34	};
35	
36	const basePremiumFor = (item: Item): number => ITEM_TYPES[item.type].basePremium;
37	
38	const countByType = (items: Item[]): Map<string, number> => {
39	  const counts = new Map<string, number>();
40	  for (const item of items) {
41	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	  }
43	  return counts;
44	};
45	
46	const premiumForTypeCount = (type: string, count: number): number => {
47	  const spec = ITEM_TYPES[type];
48	  return spec.isComponent && count === BLOCK_SIZE
49	    ? BLOCK_PREMIUM
50	    : count * spec.basePremium;
51	};
52	
53	const basePremiumOf = (items: Item[]): number => {
54	  let total = 0;
55	  for (const [type, count] of countByType(items)) {
56	    total += premiumForTypeCount(type, count);
57	  }
58	  return total;
59	};
60	
61	type SurchargeRule = { applies: (item: Item) => boolean; rate: number };
62	
63	const SURCHARGE_RULES: SurchargeRule[] = [
64	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
65	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
66	];
67	
68	const surchargeRateFor = (item: Item): number =>
69	  SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
70	
71	const itemSurchargesOf = (items: Item[]): number =>
72	  items.reduce((sum, item) => sum + basePremiumFor(item) * surchargeRateFor(item), 0);
73	
74	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
75	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
76	    ? basePremium * LOYALTY_DISCOUNT_RATE
77	    : 0;
78	
79	const followUpDiscountFor = (basePremium: number, stepIndex: number): number =>
80	  stepIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
81	
82	const quoteForStep = ({ items }: QuoteStep, customer: Customer, stepIndex: number) => {
83	  const basePremium = basePremiumOf(items);
84	  const itemSurcharges = itemSurchargesOf(items);
85	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
86	  const loyaltyDiscount = loyaltyDiscountFor(basePremium, customer);
87	  const followUpDiscount = followUpDiscountFor(basePremium, stepIndex);
88	  return {
89	    premium: Math.ceil(
90	      basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
91	    ),
92	  };
93	};
94	
95	type Policy = { items: Item[]; remainingCap: number };
96	
97	const policyFor = (items: Item[]): Policy => {
98	  const insuranceSum = items.reduce((sum, item) => sum + ITEM_TYPES[item.type].insuranceValue, 0);
99	  return { items, remainingCap: insuranceSum * CAP_MULTIPLIER };
100	};
101	
102	const insuredItemFor = (policy: Policy, damage: Damage): Item =>
103	  policy.items.find((item) => item.type === damage.itemType)!;
104	
105	const reimbursementRateFor = (item: Item): number =>
106	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
107	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
108	    : 1;
109	
110	const payoutForDamage = (policy: Policy, damage: Damage): number => {
111	  const item = insuredItemFor(policy, damage);
112	  return damage.amount * reimbursementRateFor(item) - DEDUCTIBLE;
113	};
114	
115	const claimForStep = (step: ClaimStep, policies: Map<number, Policy>) => {
116	  const policy = policies.get(step.policy)!;
117	  const desiredPayout = step.incident.damages.reduce((sum, dmg) => sum + payoutForDamage(policy, dmg), 0);
118	  const payout = Math.min(desiredPayout, policy.remainingCap);
119	  policy.remainingCap -= payout;
120	  return { payout, remainingCap: policy.remainingCap };
121	};
122	
123	export const runScenario = (scenario: Scenario): unknown => {
124	  const policies = new Map<number, Policy>();
125	  const results = scenario.steps.map((step, i) => {
126	    if (step.op === "quote") {
127	      policies.set(i, policyFor(step.items));
128	      return quoteForStep(step, scenario.customer, i);
129	    }
130	    return claimForStep(step, policies);
131	  });
132	  return { results };
133	};
